module top_module(
    input clk,
    input in,
    input reset,
    output reg out
);     // State Encoding
    parameter A = 0, B = 1;
    reg [1:0] obf_state, next;

    // State Transition Logic
    always @(*) begin
        case (obf_state)
            A: next = in ? A : B;
            B: next = in ? A : A;
        endcase
    end

    // State Register with synchronous Reset
    always @(posedge clk) begin
        if (reset) obf_state <= B;
        else obf_state <= next;
    end

    // Output Logic
    always @(*) begin
        case (obf_state)
            A: out = 0;
            B: out = 0;
        endcase
    end
endmodule
